import{_ as i,c as a,o as s,ah as t}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse(`{"title":"Guide d'utilisation GitHub","description":"","frontmatter":{},"headers":[],"relativePath":"fr/github-guide.md","filePath":"fr/github-guide.md"}`),r={name:"fr/github-guide.md"};function n(l,e,o,d,h,u){return s(),a("div",null,e[0]||(e[0]=[t(`<h1 id="guide-d-utilisation-github" tabindex="-1">Guide d&#39;utilisation GitHub <a class="header-anchor" href="#guide-d-utilisation-github" aria-label="Permalink to “Guide d&#39;utilisation GitHub”">​</a></h1><h2 id="_01-1-introduction" tabindex="-1">01.1- Introduction <a class="header-anchor" href="#_01-1-introduction" aria-label="Permalink to “01.1- Introduction”">​</a></h2><p>GitHub est la plus grande plateforme d&#39;hébergement de code au monde, fournissant aux développeurs une gestion de versions puissante, un développement collaboratif et une gestion de projets.</p><h2 id="_01-2-concepts-de-base" tabindex="-1">01.2- Concepts de base <a class="header-anchor" href="#_01-2-concepts-de-base" aria-label="Permalink to “01.2- Concepts de base”">​</a></h2><h3 id="_01-21-depot" tabindex="-1">01.21- Dépôt <a class="header-anchor" href="#_01-21-depot" aria-label="Permalink to “01.21- Dépôt”">​</a></h3><p>Un dépôt est l&#39;espace de stockage d&#39;un projet, contenant tous les fichiers, dossiers et l&#39;historique des modifications de chaque fichier.</p><h3 id="_01-22-branche" tabindex="-1">01.22- Branche <a class="header-anchor" href="#_01-22-branche" aria-label="Permalink to “01.22- Branche”">​</a></h3><p>Une branche permet de développer de nouvelles fonctionnalités ou de corriger des bugs sans affecter la branche principale.</p><h3 id="_01-23-commit" tabindex="-1">01.23- Commit <a class="header-anchor" href="#_01-23-commit" aria-label="Permalink to “01.23- Commit”">​</a></h3><p>Un commit est un enregistrement des modifications d&#39;un fichier, chaque commit se voit attribuer un identifiant unique.</p><h3 id="_01-24-pull-request" tabindex="-1">01.24- Pull Request <a class="header-anchor" href="#_01-24-pull-request" aria-label="Permalink to “01.24- Pull Request”">​</a></h3><p>Une pull request est une demande de fusion des modifications dans la branche principale, facilitant la révision du code et la discussion.</p><h2 id="_01-3-demarrage-rapide" tabindex="-1">01.3- Démarrage rapide <a class="header-anchor" href="#_01-3-demarrage-rapide" aria-label="Permalink to “01.3- Démarrage rapide”">​</a></h2><h3 id="_01-31-creation-d-un-compte" tabindex="-1">01.31- Création d&#39;un compte <a class="header-anchor" href="#_01-31-creation-d-un-compte" aria-label="Permalink to “01.31- Création d&#39;un compte”">​</a></h3><p>Visitez le <a href="https://github.com" target="_blank" rel="noreferrer">site officiel de GitHub</a> pour vous inscrire.</p><h3 id="_01-32-creation-d-un-depot" tabindex="-1">01.32- Création d&#39;un dépôt <a class="header-anchor" href="#_01-32-creation-d-un-depot" aria-label="Permalink to “01.32- Création d&#39;un dépôt”">​</a></h3><ol><li>Cliquez sur le bouton &quot;+&quot; en haut</li><li>Sélectionnez &quot;New repository&quot;</li><li>Entrez le nom et la description du dépôt</li><li>Choisissez public ou privé</li><li>Cliquez sur &quot;Create repository&quot;</li></ol><h3 id="_01-33-clonage-du-depot" tabindex="-1">01.33- Clonage du dépôt <a class="header-anchor" href="#_01-33-clonage-du-depot" aria-label="Permalink to “01.33- Clonage du dépôt”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/username/repository.git</span></span></code></pre></div><h3 id="_01-34-creation-d-une-branche" tabindex="-1">01.34- Création d&#39;une branche <a class="header-anchor" href="#_01-34-creation-d-une-branche" aria-label="Permalink to “01.34- Création d&#39;une branche”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-35-commit-des-modifications" tabindex="-1">01.35- Commit des modifications <a class="header-anchor" href="#_01-35-commit-des-modifications" aria-label="Permalink to “01.35- Commit des modifications”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Ajouter une nouvelle fonctionnalité&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-36-creation-d-une-pull-request" tabindex="-1">01.36- Création d&#39;une pull request <a class="header-anchor" href="#_01-36-creation-d-une-pull-request" aria-label="Permalink to “01.36- Création d&#39;une pull request”">​</a></h3><p>Créez une pull request sur la page GitHub et attendez la révision et la fusion.</p><h2 id="_01-4-operations-courantes" tabindex="-1">01.4- Opérations courantes <a class="header-anchor" href="#_01-4-operations-courantes" aria-label="Permalink to “01.4- Opérations courantes”">​</a></h2><h3 id="_01-41-fork" tabindex="-1">01.41- Fork <a class="header-anchor" href="#_01-41-fork" aria-label="Permalink to “01.41- Fork”">​</a></h3><p>Utilisez le fork pour copier le projet de quelqu&#39;un d&#39;autre dans votre compte et le modifier.</p><h3 id="_01-42-etoile" tabindex="-1">01.42- Étoile <a class="header-anchor" href="#_01-42-etoile" aria-label="Permalink to “01.42- Étoile”">​</a></h3><p>L&#39;étoile indique que vous aimez le projet, et vous pouvez le retrouver facilement plus tard.</p><h3 id="_01-43-watch" tabindex="-1">01.43- Watch <a class="header-anchor" href="#_01-43-watch" aria-label="Permalink to “01.43- Watch”">​</a></h3><p>Utilisez le watch pour recevoir les notifications de mise à jour du projet.</p><h3 id="_01-44-issue" tabindex="-1">01.44- Issue <a class="header-anchor" href="#_01-44-issue" aria-label="Permalink to “01.44- Issue”">​</a></h3><p>Les issues sont utilisées pour signaler des bugs, demander des fonctionnalités ou discuter d&#39;idées.</p><h2 id="_01-5-meilleures-pratiques" tabindex="-1">01.5- Meilleures pratiques <a class="header-anchor" href="#_01-5-meilleures-pratiques" aria-label="Permalink to “01.5- Meilleures pratiques”">​</a></h2><ol><li><strong>Messages de commit clairs</strong> - communiquez aux autres l&#39;objectif de chaque commit</li><li><strong>Utilisation des branches</strong> - ne développez pas directement sur la branche principale</li><li><strong>Synchronisation régulière</strong> - synchronisez le dépôt local avec le dépôt distant</li><li><strong>Révision du code</strong> - effectuez des révisions de code via les pull requests</li><li><strong>Documentation du projet</strong> - ajoutez un README et la documentation nécessaire au projet</li></ol><h2 id="_01-6-ressources-connexes" tabindex="-1">01.6- Ressources connexes <a class="header-anchor" href="#_01-6-ressources-connexes" aria-label="Permalink to “01.6- Ressources connexes”">​</a></h2><ul><li><a href="https://docs.github.com" target="_blank" rel="noreferrer">Documentation officielle GitHub</a></li><li><a href="/fr/91git.html">Guide de base Git</a></li><li><a href="/fr/全部资源概述.html">Vue d&#39;ensemble de toutes les ressources</a></li></ul>`,38)]))}const b=i(r,[["render",n]]);export{p as __pageData,b as default};
